function createRenderer() {
  function clamp(x) { return Math.max(0, Math.min(1, x)); }
  function ease(x) { x = clamp(x); return 1 - Math.pow(1 - x, 3); }
  function rr(ctx, x, y, w, h, r) { ctx.beginPath(); ctx.moveTo(x+r,y); ctx.lineTo(x+w-r,y); ctx.quadraticCurveTo(x+w,y,x+w,y+r); ctx.lineTo(x+w,y+h-r); ctx.quadraticCurveTo(x+w,y+h,x+w-r,y+h); ctx.lineTo(x+r,y+h); ctx.quadraticCurveTo(x,y+h,x,y+h-r); ctx.lineTo(x,y+r); ctx.quadraticCurveTo(x,y,x+r,y); ctx.closePath(); }
  function render(t, context) {
    var ctx = context.mainContext;
    var w = context.width;
    var h = context.height;
    var p = clamp(t / 4);
    var intro = ease(t / 1.1);
    var scan = (t * 170) % w;
    var bg = ctx.createLinearGradient(0, 0, w, h);
    bg.addColorStop(0, '#071019');
    bg.addColorStop(0.58, '#102542');
    bg.addColorStop(1, '#15251b');
    ctx.fillStyle = bg;
    ctx.fillRect(0, 0, w, h);
    ctx.save();
    ctx.globalAlpha = 0.18;
    ctx.strokeStyle = '#6ee7ff';
    ctx.lineWidth = 1;
    for (var x = -80; x < w + 80; x += 64) { ctx.beginPath(); ctx.moveTo(x + (t * 22) % 64, 0); ctx.lineTo(x - 180 + (t * 22) % 64, h); ctx.stroke(); }
    for (var y = 0; y < h; y += 64) { ctx.beginPath(); ctx.moveTo(0, y); ctx.lineTo(w, y); ctx.stroke(); }
    ctx.restore();
    ctx.save();
    ctx.globalAlpha = 0.18 + Math.sin(t * 3) * 0.04;
    ctx.fillStyle = '#00d4ff';
    ctx.beginPath(); ctx.arc(w * 0.18, h * 0.78, 170 + Math.sin(t * 2) * 16, 0, Math.PI * 2); ctx.fill();
    ctx.fillStyle = '#f2aa4c';
    ctx.beginPath(); ctx.arc(w * 0.82, h * 0.22, 190 + Math.cos(t * 1.7) * 20, 0, Math.PI * 2); ctx.fill();
    ctx.restore();
    ctx.save();
    ctx.translate(w / 2, h / 2 - 38);
    ctx.scale(0.82 + intro * 0.18, 0.82 + intro * 0.18);
    ctx.globalAlpha = intro;
    ctx.textAlign = 'center';
    ctx.textBaseline = 'middle';
    ctx.font = '900 92px Arial, sans-serif';
    ctx.fillStyle = '#ffffff';
    ctx.shadowColor = '#00d4ff';
    ctx.shadowBlur = 30;
    ctx.fillText('ui2v', 0, -64);
    ctx.shadowBlur = 0;
    ctx.font = '700 38px Arial, sans-serif';
    ctx.fillStyle = '#f2aa4c';
    ctx.fillText('FRAME-ACCURATE BROWSER VIDEO', 0, 18);
    ctx.font = '22px Arial, sans-serif';
    ctx.fillStyle = '#b8c8d8';
    ctx.fillText('JSON timeline -> Canvas render -> WebCodecs MP4', 0, 68);
    ctx.restore();
    ctx.save();
    var cardY = 520;
    var labels = [['30 FPS', String(Math.floor(t * 30)).padStart(3, '0') + ' frames'], ['CANVAS', 'deterministic draw'], ['MP4', 'browser encoded']];
    for (var i = 0; i < labels.length; i++) {
      var cp = ease((t - 0.7 - i * 0.16) / 0.55);
      var cx = 254 + i * 386;
      ctx.globalAlpha = cp;
      ctx.fillStyle = 'rgba(4, 10, 20, 0.68)';
      ctx.strokeStyle = i === 1 ? '#f2aa4c' : 'rgba(255,255,255,0.18)';
      rr(ctx, cx - 145, cardY - 58 + (1-cp)*18, 290, 116, 14);
      ctx.fill(); ctx.stroke();
      ctx.textAlign = 'center';
      ctx.font = '900 26px Arial';
      ctx.fillStyle = i === 1 ? '#f2aa4c' : '#7bd88f';
      ctx.fillText(labels[i][0], cx, cardY - 14 + (1-cp)*18);
      ctx.font = '17px Arial';
      ctx.fillStyle = '#d7e6f4';
      ctx.fillText(labels[i][1], cx, cardY + 24 + (1-cp)*18);
    }
    ctx.restore();
    ctx.save();
    ctx.globalAlpha = 0.7;
    ctx.strokeStyle = '#ffffff';
    ctx.beginPath(); ctx.moveTo(scan, 0); ctx.lineTo(scan - 140, h); ctx.stroke();
    ctx.restore();
    ctx.fillStyle = 'rgba(255,255,255,0.12)';
    rr(ctx, 120, 650, w - 240, 12, 6); ctx.fill();
    var g = ctx.createLinearGradient(120, 0, w - 120, 0); g.addColorStop(0, '#00d4ff'); g.addColorStop(1, '#f2aa4c');
    ctx.fillStyle = g; rr(ctx, 120, 650, (w - 240) * p, 12, 6); ctx.fill();
  }
  return { render: render };
}
